// ── Shared Input ──────────────────────────────────────────────────────────────
function LoginInput({icon,type,placeholder,value,onChange,error,right}){
  return(
    <div style={{marginBottom:error?6:16}}>
      <div style={{position:"relative",display:"flex",alignItems:"center"}}>
        <span style={{position:"absolute",left:14,color:error?"#ef4444":"rgba(255,255,255,0.3)",zIndex:1,display:"flex"}}>{icon}</span>
        <input type={type} placeholder={placeholder} value={value} onChange={onChange}
          style={{width:"100%",padding:"12px 14px 12px 42px",paddingRight:right?42:14,borderRadius:12,
            border:`1.5px solid ${error?"#ef4444":value?"#00c6e0":"rgba(255,255,255,0.12)"}`,
            background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:14,fontFamily:"'DM Sans',sans-serif",
            transition:"border-color 0.2s,box-shadow 0.2s",
            boxShadow:error?"0 0 0 3px rgba(239,68,68,0.1)":value?"0 0 0 3px rgba(0,198,224,0.08)":"none"}}/>
        {right&&<span style={{position:"absolute",right:14,zIndex:1}}>{right}</span>}
      </div>
      {error&&<p style={{color:"#fca5a5",fontSize:11,display:"flex",alignItems:"center",gap:4,marginTop:5}}><Icon.Alert/> {error}</p>}
    </div>
  );
}

function SubmitBtn({loading,label,onClick,type="button"}){
  return(
    <button type={type} onClick={onClick} disabled={loading}
      style={{width:"100%",padding:"14px",borderRadius:12,background:"linear-gradient(135deg,#0077b6,#00c6e0)",color:"#fff",border:"none",fontWeight:700,fontSize:15,fontFamily:"'DM Sans',sans-serif",boxShadow:"0 4px 20px rgba(0,119,182,0.4)",transition:"all 0.3s",cursor:loading?"not-allowed":"pointer",opacity:loading?0.8:1}}>
      {loading?<span style={{display:"flex",alignItems:"center",gap:8,justifyContent:"center"}}><span style={{width:16,height:16,border:"2px solid rgba(255,255,255,0.3)",borderTopColor:"#fff",borderRadius:"50%",display:"inline-block",animation:"spin 0.7s linear infinite"}}/>Please wait…</span>:label}
    </button>
  );
}

// ── Forgot Password ───────────────────────────────────────────────────────────
function ForgotPassword({onBack}){
  const [step,setStep]=useState(1),[email,setEmail]=useState(""),[otp,setOtp]=useState(["","","","","",""]),[loading,setLoading]=useState(false),[error,setError]=useState("");
  const sendOTP=()=>{if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){setError("Enter a valid email.");return;}setLoading(true);setError("");setTimeout(()=>{setLoading(false);setStep(2);},1200);};
  const verifyOTP=()=>{if(otp.join("").length<6){setError("Enter the full 6-digit code.");return;}setLoading(true);setTimeout(()=>{setLoading(false);setStep(3);},1000);};
  const handleOtp=(i,val)=>{if(!/^\d?$/.test(val))return;const n=[...otp];n[i]=val;setOtp(n);if(val&&i<5)document.getElementById(`otp-${i+1}`)?.focus();};
  return(
    <div style={{animation:"slideUp 0.4s ease"}}>
      <button onClick={onBack} style={{background:"transparent",border:"none",color:"rgba(255,255,255,0.5)",cursor:"pointer",display:"flex",alignItems:"center",gap:6,fontSize:13,marginBottom:20,fontFamily:"'DM Sans',sans-serif"}}><Icon.ArrowLeft/> Back to Login</button>
      {step===1&&<><h2 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:20,marginBottom:8}}>Forgot Password?</h2><p style={{color:"rgba(255,255,255,0.45)",fontSize:13,marginBottom:24,lineHeight:1.6}}>Enter your email and we'll send a reset code.</p><LoginInput icon={<Icon.Mail/>} type="email" placeholder="Your email address" value={email} error={error} onChange={e=>{setEmail(e.target.value);setError("");}}/><SubmitBtn loading={loading} label="Send Reset Code" onClick={sendOTP}/></>}
      {step===2&&<><h2 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:20,marginBottom:8}}>Check Your Email</h2><p style={{color:"rgba(255,255,255,0.45)",fontSize:13,marginBottom:24,lineHeight:1.6}}>Code sent to <span style={{color:"#00c6e0"}}>{email}</span></p><div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:20}}>{otp.map((v,i)=><input key={i} id={`otp-${i}`} type="text" maxLength={1} value={v} onChange={e=>handleOtp(i,e.target.value)} onKeyDown={e=>{if(e.key==="Backspace"&&!v&&i>0)document.getElementById(`otp-${i-1}`)?.focus();}} style={{width:44,height:52,borderRadius:12,border:`2px solid ${v?"#00c6e0":"rgba(255,255,255,0.15)"}`,background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:22,textAlign:"center",fontFamily:"'Cinzel',serif",outline:"none",transition:"border-color 0.2s"}}/>)}</div>{error&&<p style={{color:"#fca5a5",fontSize:11,display:"flex",alignItems:"center",gap:4,marginBottom:12}}><Icon.Alert/>{error}</p>}<SubmitBtn loading={loading} label="Verify Code" onClick={verifyOTP}/></>}
      {step===3&&<div style={{textAlign:"center",animation:"slideUp 0.4s ease"}}><div style={{width:64,height:64,borderRadius:"50%",background:"rgba(16,185,129,0.15)",border:"2px solid #10b981",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px"}}><span style={{color:"#10b981",fontSize:28}}>✓</span></div><h3 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:18,marginBottom:8}}>Code Verified!</h3><p style={{color:"rgba(255,255,255,0.45)",fontSize:13,marginBottom:24}}>Reset complete for demo purposes.</p><button onClick={onBack} style={{width:"100%",padding:"14px",borderRadius:12,background:"linear-gradient(135deg,#0077b6,#00c6e0)",color:"#fff",border:"none",fontWeight:700,fontSize:15,fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>Back to Login</button></div>}
    </div>
  );
}

