// LOGIN VIEW
// ══════════════════════════════════════════════════════════════════════════════
function LoginView({onLogin}){
  const [role,setRole]=useState("client"),[email,setEmail]=useState(""),[password,setPassword]=useState(""),[invoiceNum,setInvoiceNum]=useState(""),[showPwd,setShowPwd]=useState(false),[remember,setRemember]=useState(false),[loading,setLoading]=useState(false),[errors,setErrors]=useState({}),[shake,setShake]=useState(false),[forgot,setForgot]=useState(false),[loaded,setLoaded]=useState(false);
  useEffect(()=>{setTimeout(()=>setLoaded(true),100);},[]);
  const activeRole=ROLES.find(r=>r.key===role);
  const validate=()=>{const e={};if(role==="client"){if(!invoiceNum.trim())e.invoiceNum="Invoice number required.";else if(!invoiceNum.trim().toUpperCase().startsWith("INV-"))e.invoiceNum="Must start with INV-";}else{if(!email.trim())e.email="Email required.";else if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))e.email="Enter a valid email.";if(!password.trim())e.password="Password required.";else if(password.length<6)e.password="At least 6 characters."}return e;};
  const handleLogin=(e)=>{e?.preventDefault();const errs=validate();if(Object.keys(errs).length){setErrors(errs);setShake(true);setTimeout(()=>setShake(false),500);return;}setErrors({});setLoading(true);setTimeout(()=>{if(role==="client"){const ok=VALID_INVOICES.includes(invoiceNum.trim().toUpperCase());if(ok)onLogin(role);else{setLoading(false);setErrors({general:"Invoice not found. Try a demo number."});setShake(true);setTimeout(()=>setShake(false),500);}}else{const demo=DEMO_USERS[role];const ok=email===demo.email&&password===demo.password;if(ok)onLogin(role);else{setLoading(false);setErrors({general:"Invalid credentials. Use demo credentials below."});setShake(true);setTimeout(()=>setShake(false),500);}}},1200);};
  return(
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:16,position:"relative",overflow:"hidden"}}>
      <Particles/>
      <div style={{width:"100%",maxWidth:420,position:"relative",zIndex:1,opacity:loaded?1:0,transform:loaded?"translateY(0)":"translateY(24px)",transition:"all 0.7s cubic-bezier(0.22,1,0.36,1)"}}>
        <DCLogo size="lg"/>
        <div style={{background:"rgba(5,20,40,0.65)",backdropFilter:"blur(24px)",borderRadius:24,padding:"32px 28px",border:"1px solid rgba(0,198,224,0.12)",boxShadow:"0 20px 60px rgba(0,0,0,0.5)",animation:shake?"shake 0.5s ease":"none"}}>
          {forgot?<ForgotPassword onBack={()=>setForgot(false)}/>:<>
            <div style={{marginBottom:24}}>
              <p style={{color:"rgba(255,255,255,0.4)",fontSize:11,letterSpacing:1.5,textTransform:"uppercase",marginBottom:10}}>Sign in as</p>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
                {ROLES.map(r=>(
                  <button key={r.key} onClick={()=>{setRole(r.key);setErrors({});}} style={{padding:"11px 8px",borderRadius:12,border:`2px solid ${role===r.key?r.color:"rgba(255,255,255,0.08)"}`,background:role===r.key?`${r.color}18`:"transparent",color:role===r.key?r.color:"rgba(255,255,255,0.4)",fontFamily:"'DM Sans',sans-serif",fontSize:12,fontWeight:600,cursor:"pointer",transition:"all 0.25s",display:"flex",flexDirection:"column",alignItems:"center",gap:5}}>
                    <span style={{fontSize:18}}>{r.key==="client"?"👤":r.key==="staff"?"👔":"🛡️"}</span>{r.label}
                  </button>
                ))}
              </div>
              <p style={{color:"rgba(255,255,255,0.25)",fontSize:11,marginTop:8,textAlign:"center"}}>{activeRole?.desc}</p>
            </div>
            <form onSubmit={handleLogin}>
              {errors.general&&<div style={{padding:"11px 14px",borderRadius:10,background:"rgba(239,68,68,0.1)",border:"1px solid rgba(239,68,68,0.25)",marginBottom:16,display:"flex",alignItems:"flex-start",gap:8}}><span style={{color:"#ef4444",flexShrink:0,marginTop:1}}><Icon.Alert/></span><p style={{color:"#fca5a5",fontSize:12,lineHeight:1.5}}>{errors.general}</p></div>}
              {role==="client"?<>
                <LoginInput icon={<Icon.Invoice/>} type="text" placeholder="Invoice number (e.g. INV-001)" value={invoiceNum} error={errors.invoiceNum} onChange={e=>{setInvoiceNum(e.target.value.toUpperCase());setErrors(p=>({...p,invoiceNum:"",general:""}));}}/>
                <div style={{padding:"11px 14px",borderRadius:10,background:"rgba(0,198,224,0.05)",border:"1px solid rgba(0,198,224,0.12)",marginBottom:16}}><p style={{color:"rgba(255,255,255,0.4)",fontSize:12,lineHeight:1.6}}>📄 Your invoice number is on your receipt. Contact us on WhatsApp if needed.</p></div>
              </>:<>
                <LoginInput icon={<Icon.Mail/>} type="email" placeholder="Email address" value={email} error={errors.email} onChange={e=>{setEmail(e.target.value);setErrors(p=>({...p,email:"",general:""}));}}/>
                <LoginInput icon={<Icon.Lock/>} type={showPwd?"text":"password"} placeholder="Password" value={password} error={errors.password} onChange={e=>{setPassword(e.target.value);setErrors(p=>({...p,password:"",general:""}));}} right={<button type="button" onClick={()=>setShowPwd(s=>!s)} style={{background:"transparent",border:"none",cursor:"pointer",color:"rgba(255,255,255,0.35)",display:"flex",alignItems:"center",padding:0}}>{showPwd?<Icon.EyeOff/>:<Icon.Eye/>}</button>}/>
              </>}
              {role!=="client"&&<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}} onClick={()=>setRemember(r=>!r)}><div style={{width:18,height:18,borderRadius:5,border:`2px solid ${remember?"#00c6e0":"rgba(255,255,255,0.2)"}`,background:remember?"#00c6e0":"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.2s",flexShrink:0}}>{remember&&<Icon.Check/>}</div><span style={{color:"rgba(255,255,255,0.45)",fontSize:13}}>Remember me</span></label><button type="button" onClick={()=>{setForgot(true);setErrors({});}} style={{background:"transparent",border:"none",color:"#00c6e0",fontSize:13,cursor:"pointer",fontFamily:"'DM Sans',sans-serif",fontWeight:600}}>Forgot password?</button></div>}
              <SubmitBtn loading={loading} label="Sign In" type="submit"/>
