                <div style={{display:"flex",flexWrap:"wrap",gap:6}}>{VALID_INVOICES.map(inv=><span key={inv} onClick={()=>setInvoiceNum(inv)} style={{padding:"3px 10px",borderRadius:20,background:"rgba(0,198,224,0.1)",border:"1px solid rgba(0,198,224,0.2)",color:"#00c6e0",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"monospace"}}>{inv}</span>)}</div>
                <p style={{color:"rgba(255,255,255,0.2)",fontSize:10,marginTop:6}}>Click any to auto-fill</p>
              </>:<>
                <p style={{color:"rgba(255,255,255,0.35)",fontSize:11,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Demo Credentials</p>
                {ROLES.filter(r=>r.key!=="client").map(r=><div key={r.key} style={{display:"flex",justifyContent:"space-between",marginBottom:4}}><span style={{color:r.color,fontSize:11,fontWeight:700}}>{r.label}</span><span style={{color:"rgba(255,255,255,0.3)",fontSize:11,fontFamily:"monospace"}}>{DEMO_USERS[r.key].email.split("@")[0]} / {DEMO_USERS[r.key].password}</span></div>)}
              </>}
            </div>
          </>}
        </div>
        <p style={{textAlign:"center",color:"rgba(255,255,255,0.2)",fontSize:12,marginTop:20}}>© {new Date().getFullYear()} <span style={{color:"rgba(255,255,255,0.35)",fontFamily:"'Cinzel',serif"}}>Deep Citadel</span> · Powerful Clean. Trusted Care.</p>
