// OWNER DASHBOARD — Service & Price Manager
// ══════════════════════════════════════════════════════════════════════════════
function OwnerDashboard({onLogout}){
  const loadServices=()=>{
    try{const s=localStorage.getItem(PRICE_KEY);const p=s?JSON.parse(s):DEFAULT_PRICES;
      return Object.entries(p).map(([name,price],i)=>({id:Date.now()+i,name,price,enabled:true,...(DEFAULT_META[name]||{icon:"Wash",accent:"#00c6e0"})}));}
    catch{return Object.entries(DEFAULT_PRICES).map(([name,price],i)=>({id:Date.now()+i,name,price,enabled:true,...(DEFAULT_META[name]||{icon:"Wash",accent:"#00c6e0"})}))}
  };
  const [ownerView,setOwnerView]=useState("dashboard");
  const [services,setServices]=useState(loadServices);
  const [editingId,setEditingId]=useState(null);
  const [showAddModal,setShowAddModal]=useState(false);
  const [saveFlash,setSaveFlash]=useState(false);
  const [newSvc,setNewSvc]=useState({name:"",price:"",icon:"Wash",accent:"#00c6e0"});
  const [newErr,setNewErr]=useState({});

  // Owner acting as staff — render POS inline
  if(ownerView==="pos"){
    return <POSView role="owner" onLogout={onLogout} onBack={()=>setOwnerView("dashboard")}/>;
  }

  const saveToStorage=(svcs)=>{
    const obj=Object.fromEntries(svcs.filter(s=>s.enabled).map(s=>[s.name,parseFloat(s.price)]));
    localStorage.setItem(PRICE_KEY,JSON.stringify(obj));
    setSaveFlash(true);setTimeout(()=>setSaveFlash(false),1800);
  };

  const updateService=(id,field,val)=>setServices(prev=>prev.map(s=>s.id===id?{...s,[field]:val}:s));

  const deleteService=(id)=>setServices(prev=>prev.filter(s=>s.id!==id));

  const toggleEnabled=(id)=>setServices(prev=>prev.map(s=>s.id===id?{...s,enabled:!s.enabled}:s));

  const handleSave=()=>saveToStorage(services);

  const validateNew=()=>{const e={};if(!newSvc.name.trim())e.name="Service name required.";else if(services.find(s=>s.name.toLowerCase()===newSvc.name.trim().toLowerCase()))e.name="Service already exists.";if(!newSvc.price||isNaN(parseFloat(newSvc.price))||parseFloat(newSvc.price)<0)e.price="Enter a valid price.";return e;};

  const addService=()=>{const e=validateNew();if(Object.keys(e).length){setNewErr(e);return;}const s={id:Date.now(),name:newSvc.name.trim(),price:parseFloat(newSvc.price),icon:newSvc.icon,accent:newSvc.accent,enabled:true};setServices(prev=>[...prev,s]);setShowAddModal(false);setNewSvc({name:"",price:"",icon:"Wash",accent:"#00c6e0"});setNewErr({});};

  const totalActive=services.filter(s=>s.enabled).length;

  return(
    <div style={{position:"relative",zIndex:1,minHeight:"100vh",fontFamily:"'DM Sans',sans-serif",padding:"22px 28px",color:"#e8f4f8"}}>

      {/* Header */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:28}}>
        <div style={{display:"flex",alignItems:"center",gap:14}}>
          <DCLogo size="sm"/>
          <div style={{marginLeft:4}}>
            <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:20,color:"#fff",letterSpacing:0.5}}>Deep Citadel</div>
            <div style={{display:"flex",gap:6,marginTop:4}}>
              {[{id:"dashboard",label:"⚙️  Dashboard"},{id:"pos",label:"🧺  POS Terminal"}].map(tab=>(
                <button key={tab.id} onClick={()=>setOwnerView(tab.id)}
                  style={{padding:"3px 12px",borderRadius:20,border:`1px solid ${ownerView===tab.id?"rgba(245,158,11,0.5)":"rgba(255,255,255,0.1)"}`,background:ownerView===tab.id?"rgba(245,158,11,0.15)":"transparent",color:ownerView===tab.id?"#f59e0b":"rgba(255,255,255,0.35)",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"'DM Sans',sans-serif",letterSpacing:0.5,transition:"all 0.2s"}}>
                  {tab.label}
                </button>
              ))}
            </div>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <div style={{background:"rgba(245,158,11,0.15)",border:"1px solid rgba(245,158,11,0.3)",color:"#f59e0b",fontSize:11,fontWeight:600,letterSpacing:1.5,padding:"5px 14px",borderRadius:20,textTransform:"uppercase"}}>🛡️ Owner</div>
          <button onClick={onLogout} style={{display:"flex",alignItems:"center",gap:7,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.1)",color:"rgba(255,255,255,0.5)",borderRadius:10,padding:"7px 14px",cursor:"pointer",fontSize:12,fontFamily:"'DM Sans',sans-serif",transition:"all 0.2s"}} onMouseEnter={e=>{e.currentTarget.style.color="#fff";e.currentTarget.style.borderColor="rgba(255,255,255,0.25)";}} onMouseLeave={e=>{e.currentTarget.style.color="rgba(255,255,255,0.5)";e.currentTarget.style.borderColor="rgba(255,255,255,0.1)";}}>
            <Icon.SignOut/> Sign Out
          </button>
        </div>
      </div>

      {/* Stats row */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:16,marginBottom:24}}>
        {[
          {label:"Total Services",value:services.length,color:"#00c6e0",icon:"⚙️"},
          {label:"Active Services",value:totalActive,color:"#10b981",icon:"✅"},
          {label:"Disabled Services",value:services.length-totalActive,color:"#f59e0b",icon:"⏸️"},
        ].map(stat=>(
          <div key={stat.label} style={{background:"rgba(5,25,45,0.65)",border:`1px solid ${stat.color}22`,borderRadius:16,padding:"18px 20px",backdropFilter:"blur(20px)",boxShadow:"0 4px 20px rgba(0,0,0,0.3)"}}>
            <div style={{fontSize:22,marginBottom:6}}>{stat.icon}</div>
            <div style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:28,color:stat.color}}>{stat.value}</div>
            <div style={{fontSize:12,color:"rgba(255,255,255,0.4)",marginTop:2,letterSpacing:0.5}}>{stat.label}</div>
          </div>
        ))}
      </div>

      {/* Main panel */}
      <div style={{background:"rgba(5,25,45,0.65)",border:"1px solid rgba(0,198,224,0.12)",borderRadius:20,backdropFilter:"blur(20px)",padding:24,boxShadow:"0 8px 40px rgba(0,0,0,0.4),inset 0 1px 0 rgba(255,255,255,0.05)"}}>

        {/* Panel header */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
          <div>
            <div style={{fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:16,color:"#fff"}}>Service & Price Management</div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",marginTop:3}}>Edit prices, toggle availability, add or remove services</div>
          </div>
          <div style={{display:"flex",gap:10}}>
            <button onClick={()=>setShowAddModal(true)}
              style={{display:"flex",alignItems:"center",gap:7,padding:"10px 18px",borderRadius:11,border:"none",background:"linear-gradient(135deg,#0077b6,#00c6e0)",color:"#fff",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:13,cursor:"pointer",boxShadow:"0 3px 14px rgba(0,198,224,0.3)",transition:"all 0.2s"}}
              onMouseEnter={e=>e.currentTarget.style.transform="translateY(-1px)"}
              onMouseLeave={e=>e.currentTarget.style.transform="translateY(0)"}>
              <Icon.Plus/> Add Service
            </button>
            <button onClick={handleSave}
              style={{display:"flex",alignItems:"center",gap:7,padding:"10px 18px",borderRadius:11,border:"none",background:saveFlash?"linear-gradient(135deg,#059669,#10b981)":"linear-gradient(135deg,#10b981,#34d399)",color:"#fff",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:13,cursor:"pointer",boxShadow:"0 3px 14px rgba(16,185,129,0.3)",transition:"all 0.3s"}}
              onMouseEnter={e=>e.currentTarget.style.transform="translateY(-1px)"}
              onMouseLeave={e=>e.currentTarget.style.transform="translateY(0)"}>
              <Icon.Save/> {saveFlash?"Saved ✓":"Save Changes"}
            </button>
          </div>
        </div>

        {/* Column headers */}
        <div style={{display:"grid",gridTemplateColumns:"2fr 1.2fr 1fr 1fr 80px",gap:12,padding:"8px 16px",marginBottom:8}}>
          {["Service Name","Price (GHS)","Icon","Color","Actions"].map(h=><div key={h} style={{fontSize:10,color:"rgba(255,255,255,0.3)",textTransform:"uppercase",letterSpacing:1.2,fontWeight:600}}>{h}</div>)}
        </div>

        {/* Service rows */}
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {services.map(svc=>{
            const SvcIcon=Icon[svc.icon]||Icon.Wash;
            const isEditing=editingId===svc.id;
            return(
              <div key={svc.id} style={{display:"grid",gridTemplateColumns:"2fr 1.2fr 1fr 1fr 80px",gap:12,alignItems:"center",background:svc.enabled?"rgba(255,255,255,0.04)":"rgba(255,255,255,0.015)",border:`1px solid ${svc.enabled?svc.accent+"33":"rgba(255,255,255,0.06)"}`,borderRadius:14,padding:"12px 16px",transition:"all 0.2s",opacity:svc.enabled?1:0.5,borderLeft:`3px solid ${svc.enabled?svc.accent:"rgba(255,255,255,0.1)"}`,animation:"sIn 0.2s ease"}}>

                {/* Name */}
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{width:34,height:34,borderRadius:9,background:"rgba(255,255,255,0.05)",border:`1px solid ${svc.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",color:svc.accent,flexShrink:0}}>
                    <SvcIcon/>
                  </div>
                  {isEditing
                    ?<input autoFocus value={svc.name} onChange={e=>updateService(svc.id,"name",e.target.value)} style={{background:"rgba(0,0,0,0.3)",border:`1px solid ${svc.accent}`,borderRadius:8,padding:"6px 10px",color:"#fff",fontSize:13,fontFamily:"'DM Sans',sans-serif",width:"100%"}}/>
                    :<span style={{fontSize:13,fontFamily:"'Syne',sans-serif",fontWeight:600,color:svc.enabled?"#e8f4f8":"rgba(255,255,255,0.4)"}}>{svc.name}</span>
                  }
                </div>

                {/* Price */}
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <span style={{color:"rgba(255,255,255,0.3)",fontSize:13}}>₵</span>
                  <input type="number" min="0" step="0.5" value={svc.price}
                    onChange={e=>updateService(svc.id,"price",e.target.value)}
                    style={{background:"rgba(0,0,0,0.3)",border:`1px solid ${isEditing?svc.accent:"rgba(255,255,255,0.1)"}`,borderRadius:8,padding:"6px 10px",color:svc.accent,fontSize:14,fontFamily:"'Syne',sans-serif",fontWeight:700,width:"100%",transition:"border-color 0.2s"}}
                    onFocus={e=>e.target.style.borderColor=svc.accent}
                    onBlur={e=>e.target.style.borderColor="rgba(255,255,255,0.1)"}/>
                </div>

                {/* Icon picker */}
                <select value={svc.icon} onChange={e=>updateService(svc.id,"icon",e.target.value)}
                  style={{background:"rgba(0,0,0,0.4)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:8,padding:"6px 8px",color:"rgba(255,255,255,0.7)",fontSize:12,fontFamily:"'DM Sans',sans-serif",cursor:"pointer",width:"100%"}}>
                  {ICON_OPTIONS.map(ic=><option key={ic} value={ic}>{ic}</option>)}
                </select>

                {/* Color picker */}
                <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                  {ACCENT_OPTIONS.map(c=>(
                    <div key={c} onClick={()=>updateService(svc.id,"accent",c)}
                      style={{width:18,height:18,borderRadius:"50%",background:c,cursor:"pointer",border:`2px solid ${svc.accent===c?"#fff":"transparent"}`,transition:"border 0.15s",flexShrink:0}}/>
                  ))}
                </div>

                {/* Actions */}
                <div style={{display:"flex",gap:6,justifyContent:"flex-end"}}>
                  <button onClick={()=>setEditingId(isEditing?null:svc.id)}
                    title={isEditing?"Done editing":"Edit name"}
                    style={{width:28,height:28,borderRadius:7,border:`1px solid ${isEditing?"#00c6e0":"rgba(255,255,255,0.12)"}`,background:isEditing?"rgba(0,198,224,0.15)":"rgba(255,255,255,0.04)",color:isEditing?"#00c6e0":"rgba(255,255,255,0.4)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.15s"}}>
                    {isEditing?<Icon.Check/>:<Icon.Edit/>}
                  </button>
                  <button onClick={()=>toggleEnabled(svc.id)}
                    title={svc.enabled?"Disable service":"Enable service"}
                    style={{width:28,height:28,borderRadius:7,border:`1px solid ${svc.enabled?"rgba(16,185,129,0.3)":"rgba(255,255,255,0.1)"}`,background:svc.enabled?"rgba(16,185,129,0.1)":"rgba(255,255,255,0.03)",color:svc.enabled?"#10b981":"rgba(255,255,255,0.3)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,transition:"all 0.15s"}}>
                    {svc.enabled?"✓":"○"}
                  </button>
                  <button onClick={()=>deleteService(svc.id)}
                    title="Delete service"
                    style={{width:28,height:28,borderRadius:7,border:"1px solid rgba(239,68,68,0.2)",background:"rgba(239,68,68,0.08)",color:"#ef4444",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.15s"}}
                    onMouseEnter={e=>e.currentTarget.style.background="rgba(239,68,68,0.2)"}
                    onMouseLeave={e=>e.currentTarget.style.background="rgba(239,68,68,0.08)"}>
                    <Icon.Trash/>
                  </button>
                </div>
              </div>
            );
          })}
        </div>

        {services.length===0&&<div style={{textAlign:"center",color:"rgba(255,255,255,0.2)",padding:"40px 0",fontSize:14}}>No services yet. Add one above.</div>}

        <div style={{marginTop:16,padding:"11px 14px",borderRadius:10,background:"rgba(245,158,11,0.05)",border:"1px solid rgba(245,158,11,0.15)",display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:14}}>💡</span>
          <p style={{fontSize:12,color:"rgba(255,255,255,0.35)",lineHeight:1.5}}>Edit prices directly in the price field. Click <b style={{color:"rgba(255,255,255,0.5)"}}>Edit</b> to rename a service. Toggle the green/grey button to enable or disable it on the POS. Press <b style={{color:"#10b981"}}>Save Changes</b> to apply.</p>
        </div>
      </div>

      {/* Add Service Modal */}
      {showAddModal&&(
        <div style={{position:"fixed",inset:0,zIndex:100,display:"flex",alignItems:"center",justifyContent:"center",background:"rgba(0,0,0,0.7)",backdropFilter:"blur(6px)",padding:16}}>
          <div style={{background:"rgba(5,20,45,0.98)",border:"1px solid rgba(0,198,224,0.2)",borderRadius:20,padding:28,width:"100%",maxWidth:440,boxShadow:"0 20px 60px rgba(0,0,0,0.7)",animation:"popIn 0.25s ease"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:22}}>
              <h3 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:18}}>Add New Service</h3>
              <button onClick={()=>{setShowAddModal(false);setNewErr({});setNewSvc({name:"",price:"",icon:"Wash",accent:"#00c6e0"});}} style={{background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.1)",color:"rgba(255,255,255,0.5)",borderRadius:8,width:32,height:32,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><Icon.Close/></button>
            </div>

            {/* Name */}
            <label style={{display:"block",fontSize:11,color:"rgba(255,255,255,0.4)",letterSpacing:1,textTransform:"uppercase",marginBottom:6}}>Service Name</label>
            <input value={newSvc.name} onChange={e=>{setNewSvc(p=>({...p,name:e.target.value}));setNewErr(p=>({...p,name:""}));}} placeholder="e.g. Express Wash" style={{width:"100%",padding:"11px 14px",borderRadius:10,border:`1.5px solid ${newErr.name?"#ef4444":"rgba(255,255,255,0.12)"}`,background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:14,fontFamily:"'DM Sans',sans-serif",marginBottom:4}}/>
            {newErr.name&&<p style={{color:"#fca5a5",fontSize:11,marginBottom:8,display:"flex",alignItems:"center",gap:4}}><Icon.Alert/>{newErr.name}</p>}

            {/* Price */}
            <label style={{display:"block",fontSize:11,color:"rgba(255,255,255,0.4)",letterSpacing:1,textTransform:"uppercase",margin:"12px 0 6px"}}>Price (GHS ₵)</label>
            <input type="number" min="0" step="0.5" value={newSvc.price} onChange={e=>{setNewSvc(p=>({...p,price:e.target.value}));setNewErr(p=>({...p,price:""}));}} placeholder="0.00" style={{width:"100%",padding:"11px 14px",borderRadius:10,border:`1.5px solid ${newErr.price?"#ef4444":"rgba(255,255,255,0.12)"}`,background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:14,fontFamily:"'DM Sans',sans-serif",marginBottom:4}}/>
            {newErr.price&&<p style={{color:"#fca5a5",fontSize:11,marginBottom:8,display:"flex",alignItems:"center",gap:4}}><Icon.Alert/>{newErr.price}</p>}

            {/* Icon */}
            <label style={{display:"block",fontSize:11,color:"rgba(255,255,255,0.4)",letterSpacing:1,textTransform:"uppercase",margin:"12px 0 8px"}}>Icon</label>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:16}}>
              {ICON_OPTIONS.map(ic=>{const IC=Icon[ic]||Icon.Wash;return(
                <div key={ic} onClick={()=>setNewSvc(p=>({...p,icon:ic}))}
                  style={{width:40,height:40,borderRadius:10,border:`2px solid ${newSvc.icon===ic?newSvc.accent:"rgba(255,255,255,0.1)"}`,background:newSvc.icon===ic?`${newSvc.accent}22`:"rgba(255,255,255,0.04)",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:newSvc.icon===ic?newSvc.accent:"rgba(255,255,255,0.4)",transition:"all 0.15s"}}>
                  <IC/>
                </div>
              );})}
            </div>

            {/* Accent color */}
            <label style={{display:"block",fontSize:11,color:"rgba(255,255,255,0.4)",letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Accent Color</label>
            <div style={{display:"flex",gap:10,marginBottom:24,flexWrap:"wrap"}}>
              {ACCENT_OPTIONS.map(c=>(
                <div key={c} onClick={()=>setNewSvc(p=>({...p,accent:c}))}
                  style={{width:26,height:26,borderRadius:"50%",background:c,cursor:"pointer",border:`3px solid ${newSvc.accent===c?"#fff":"transparent"}`,transition:"border 0.15s"}}/>
              ))}
            </div>

            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>{setShowAddModal(false);setNewErr({});setNewSvc({name:"",price:"",icon:"Wash",accent:"#00c6e0"});}} style={{flex:1,padding:"12px",borderRadius:11,border:"1px solid rgba(255,255,255,0.1)",background:"rgba(255,255,255,0.04)",color:"rgba(255,255,255,0.5)",fontFamily:"'Syne',sans-serif",fontWeight:600,fontSize:13,cursor:"pointer"}}>Cancel</button>
              <button onClick={addService} style={{flex:2,padding:"12px",borderRadius:11,border:"none",background:"linear-gradient(135deg,#0077b6,#00c6e0)",color:"#fff",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:13,cursor:"pointer",boxShadow:"0 3px 14px rgba(0,198,224,0.3)"}}>Add Service</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// POS VIEW (Staff + Client)
// ══════════════════════════════════════════════════════════════════════════════
function POSView({role,onLogout,onBack=null}){
  const [activePrices]=useState(()=>{try{const s=localStorage.getItem(PRICE_KEY);return s?JSON.parse(s):DEFAULT_PRICES;}catch{return DEFAULT_PRICES;}});
  const services=Object.keys(activePrices);
  const [quantities,setQuantities]=useState(()=>Object.fromEntries(services.map(k=>[k,0])));
  const [cart,setCart]=useState([]);
  const [customer,setCustomer]=useState({name:"",phone:""});
  const totalAmount=cart.reduce((s,i)=>s+i.subtotal,0);
  const totalItems=cart.reduce((s,i)=>s+i.qty,0);
  const hasQty=Object.values(quantities).some(q=>q>0);
  const roleColor=ROLES.find(r=>r.key===role)?.color||"#00c6e0";
  const setQty=(service,val)=>{const n=Math.max(0,Math.min(99,isNaN(parseInt(val))?0:parseInt(val)));setQuantities(prev=>({...prev,[service]:n}));};
  const buildOrder=()=>{setCart(Object.entries(quantities).filter(([,q])=>q>0).map(([name,qty])=>({id:`${name}-${Date.now()}`,name,qty,unitPrice:activePrices[name]||0,subtotal:qty*(activePrices[name]||0)})));};
  const removeFromCart=(id)=>{const item=cart.find(i=>i.id===id);if(item)setQty(item.name,0);setCart(prev=>prev.filter(i=>i.id!==id));};
  const clearAll=()=>{setCart([]);setQuantities(Object.fromEntries(services.map(k=>[k,0])));};
  return(
    <div style={{position:"relative",zIndex:1,minHeight:"100vh",fontFamily:"'DM Sans',sans-serif",padding:"22px 28px",color:"#e8f4f8"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:24}}>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <DCLogo size="sm"/>
          <div style={{marginLeft:4}}>
            <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:20,color:"#fff",letterSpacing:0.5}}>Deep Citadel</div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.35)",letterSpacing:2,textTransform:"uppercase"}}>Point of Sale</div>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div style={{background:`${roleColor}18`,border:`1px solid ${roleColor}44`,color:roleColor,fontSize:11,fontWeight:600,letterSpacing:1.5,padding:"5px 14px",borderRadius:20,textTransform:"uppercase"}}>● {role}</div>
          <button onClick={onLogout} style={{display:"flex",alignItems:"center",gap:7,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.1)",color:"rgba(255,255,255,0.5)",borderRadius:10,padding:"7px 14px",cursor:"pointer",fontSize:12,fontFamily:"'DM Sans',sans-serif",transition:"all 0.2s"}} onMouseEnter={e=>{e.currentTarget.style.color="#fff";e.currentTarget.style.borderColor="rgba(255,255,255,0.25)";}} onMouseLeave={e=>{e.currentTarget.style.color="rgba(255,255,255,0.5)";e.currentTarget.style.borderColor="rgba(255,255,255,0.1)";}}>
            <Icon.SignOut/> Sign Out
          </button>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1.3fr 1fr",gap:22}}>
        <div style={{background:"rgba(5,25,45,0.62)",border:"1px solid rgba(0,198,224,0.12)",borderRadius:20,backdropFilter:"blur(20px)",padding:24,boxShadow:"0 8px 40px rgba(0,0,0,0.4),inset 0 1px 0 rgba(255,255,255,0.05)"}}>
          <div style={{fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:15,color:"#fff",letterSpacing:-0.3}}>Select Services</div>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",margin:"3px 0 20px"}}>Enter quantity per service, then add to order</div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {services.map(service=>{
              const meta=DEFAULT_META[service]||{icon:"Wash",accent:"#00c6e0"};
              const SvcIcon=Icon[meta.icon]||Icon.Wash;
              const qty=quantities[service]||0;
              return(
                <div key={service} style={{display:"flex",alignItems:"center",gap:14,background:qty>0?"rgba(255,255,255,0.055)":"rgba(255,255,255,0.03)",border:`${qty>0?"2":"1"}px solid ${qty>0?meta.accent+"44":"rgba(255,255,255,0.07)"}`,borderRadius:14,padding:"13px 16px",borderLeft:`3px solid ${qty>0?meta.accent:"rgba(255,255,255,0.07)"}`,transition:"all 0.2s"}}>
                  <div style={{width:40,height:40,borderRadius:11,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.08)",color:meta.accent}}><SvcIcon/></div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontFamily:"'Syne',sans-serif",fontWeight:600,fontSize:13.5,color:"#e8f4f8"}}>{service}</div>
                    <div style={{fontSize:12,color:meta.accent,marginTop:2}}>₵{(activePrices[service]||0).toFixed(2)} per item</div>
                    {qty>0&&<div style={{fontSize:11,color:"rgba(255,255,255,0.38)",marginTop:2}}>→ ₵{(qty*(activePrices[service]||0)).toFixed(2)}</div>}
                  </div>
                  <div style={{display:"flex",alignItems:"center",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:10,overflow:"hidden",flexShrink:0}}>
                    <button onClick={()=>setQty(service,qty-1)} style={{width:32,height:36,border:"none",background:"transparent",color:"rgba(255,255,255,0.45)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}} onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.08)"} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><Icon.Minus/></button>
                    <input type="number" min="0" max="99" value={qty===0?"":qty} placeholder="0" onChange={e=>setQty(service,e.target.value)} style={{width:44,height:36,background:"transparent",border:"none",borderLeft:"1px solid rgba(255,255,255,0.08)",borderRight:"1px solid rgba(255,255,255,0.08)",color:"#fff",textAlign:"center",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:14,outline:"none"}}/>
                    <button onClick={()=>setQty(service,qty+1)} style={{width:32,height:36,border:"none",background:"transparent",color:"rgba(255,255,255,0.45)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}} onMouseEnter={e=>{e.currentTarget.style.background="rgba(0,198,224,0.2)";e.currentTarget.style.color="#00c6e0";}} onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color="rgba(255,255,255,0.45)"}}><Icon.Plus/></button>
                  </div>
                </div>
              );
            })}
          </div>
          <button onClick={buildOrder} disabled={!hasQty} style={{width:"100%",marginTop:18,padding:13,borderRadius:12,border:"none",background:hasQty?"linear-gradient(135deg,#0077b6,#00c6e0)":"rgba(255,255,255,0.05)",color:hasQty?"#fff":"rgba(255,255,255,0.2)",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:13.5,cursor:hasQty?"pointer":"not-allowed",display:"flex",alignItems:"center",justifyContent:"center",gap:8,transition:"all 0.2s",boxShadow:hasQty?"0 4px 18px rgba(0,198,224,0.28)":"none"}}>
            <Icon.Cart/> Add to Order
          </button>
        </div>
        <div style={{background:"rgba(5,25,45,0.62)",border:"1px solid rgba(0,198,224,0.12)",borderRadius:20,backdropFilter:"blur(20px)",padding:24,boxShadow:"0 8px 40px rgba(0,0,0,0.4),inset 0 1px 0 rgba(255,255,255,0.05)"}}>
          <div style={{display:"flex",alignItems:"center",marginBottom:3}}>
            <div style={{fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:15,color:"#fff"}}>Order Summary</div>
            {cart.length>0&&<span style={{background:"rgba(0,198,224,0.15)",border:"1px solid rgba(0,198,224,0.25)",color:"#00c6e0",borderRadius:6,padding:"2px 8px",fontSize:11,fontWeight:600,marginLeft:8}}>{totalItems} item{totalItems!==1?"s":""}</span>}
          </div>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",margin:"3px 0 16px"}}>Customer details &amp; order breakdown</div>
          {["name","phone"].map(field=>(
            <div key={field} style={{display:"flex",alignItems:"center",gap:10,background:"rgba(0,0,0,0.25)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:10,padding:"11px 14px",marginBottom:8,transition:"border-color 0.2s"}} onFocus={e=>e.currentTarget.style.borderColor="rgba(0,198,224,0.35)"} onBlur={e=>e.currentTarget.style.borderColor="rgba(255,255,255,0.07)"}>
              <span style={{color:"rgba(0,198,224,0.6)",flexShrink:0}}>{field==="name"?<Icon.User/>:<Icon.Phone/>}</span>
              <input placeholder={field==="name"?"Customer Name":"Phone Number"} value={customer[field]} onChange={e=>setCustomer({...customer,[field]:e.target.value})} style={{background:"transparent",border:"none",outline:"none",color:"#e8f4f8",fontFamily:"'DM Sans',sans-serif",fontSize:13.5,width:"100%"}}/>
            </div>
          ))}
          <div style={{borderTop:"1px solid rgba(255,255,255,0.07)",margin:"14px 0"}}/>
          <div style={{minHeight:160}}>
            {cart.length===0?<div style={{textAlign:"center",color:"rgba(255,255,255,0.18)",fontSize:13,padding:"38px 0",lineHeight:1.7}}>Set quantities on the left<br/>then tap Add to Order</div>:cart.map(item=>(
              <div key={item.id} style={{display:"grid",gridTemplateColumns:"1fr auto auto",alignItems:"center",gap:10,padding:"9px 0",borderBottom:"1px solid rgba(255,255,255,0.05)",animation:"sIn 0.2s ease"}}>
                <div><div style={{color:"rgba(255,255,255,0.8)",fontSize:13}}>{item.name}</div><div style={{fontSize:11,color:"rgba(255,255,255,0.32)",marginTop:2}}>{item.qty} × ₵{item.unitPrice.toFixed(2)}</div></div>
                <div style={{color:"#00c6e0",fontWeight:700,fontFamily:"'Syne',sans-serif",fontSize:13}}>₵{item.subtotal.toFixed(2)}</div>
                <button onClick={()=>removeFromCart(item.id)} style={{background:"rgba(239,68,68,0.1)",border:"1px solid rgba(239,68,68,0.2)",color:"#ef4444",borderRadius:6,width:26,height:26,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}} onMouseEnter={e=>e.currentTarget.style.background="rgba(239,68,68,0.25)"} onMouseLeave={e=>e.currentTarget.style.background="rgba(239,68,68,0.1)"}><Icon.Trash/></button>
              </div>
            ))}
          </div>
          <div style={{marginTop:16,paddingTop:16,borderTop:"1px dashed rgba(0,198,224,0.2)"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:14}}>
              <span style={{fontSize:12,color:"rgba(255,255,255,0.4)",textTransform:"uppercase",letterSpacing:1.5}}>Total Due</span>
              <span style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:26,color:"#00c6e0",textShadow:"0 0 20px rgba(0,198,224,0.5)"}}>₵{totalAmount.toFixed(2)}</span>
            </div>
            <div style={{display:"flex",gap:10}}>
              <button onClick={clearAll} disabled={cart.length===0} style={{padding:"13px 16px",borderRadius:12,border:"1px solid rgba(255,255,255,0.1)",background:"rgba(255,255,255,0.04)",color:cart.length===0?"rgba(255,255,255,0.2)":"rgba(255,255,255,0.5)",fontFamily:"'Syne',sans-serif",fontWeight:600,fontSize:13,cursor:cart.length===0?"not-allowed":"pointer",flexShrink:0}}>Clear</button>
              <button disabled={cart.length===0} style={{flex:1,padding:13,borderRadius:12,border:"none",background:cart.length>0?"linear-gradient(135deg,#10b981,#059669)":"rgba(255,255,255,0.05)",color:cart.length>0?"#fff":"rgba(255,255,255,0.2)",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:13.5,cursor:cart.length>0?"pointer":"not-allowed",display:"flex",alignItems:"center",justifyContent:"center",gap:8,boxShadow:cart.length>0?"0 4px 18px rgba(16,185,129,0.3)":"none"}}>
                <Icon.Print/> Process &amp; Print
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// ROOT APP
// ══════════════════════════════════════════════════════════════════════════════
export default function DeepCitadelApp(){
  const [session,setSession]=useState(null);
  return(
    <>
      <style>{CSS}</style>
      <DeepCitadelBackground/>
      {!session && <LoginView onLogin={setSession}/>}
      {session==="owner" && <OwnerDashboard onLogout={()=>setSession(null)}/>}
      {(session==="staff"||session==="client") && <POSView role={session} onLogout={()=>setSession(null)}/>}
    </>
  );
}
